#!/usr/bin/env python3
from __future__ import annotations
import re
import sys
from pathlib import Path

root = Path(sys.argv[1]).resolve()
player_path = root / "src/client/game/util/player_animations.ts"
hud_path = root / "src/client/components/challenges/HarthmereUnifiedHUD.tsx"
npcs_path = root / "src/client/game/resources/npcs.ts"
renderer_path = root / "src/client/game/renderers/local_dev/harthmere_assets.ts"
multi_path = root / "src/client/components/challenges/LocalDevHarthmereMultiplayerCombatSystem.tsx"

player = player_path.read_text(encoding="utf-8")
hud = hud_path.read_text(encoding="utf-8")
npcs = npcs_path.read_text(encoding="utf-8")
renderer = renderer_path.read_text(encoding="utf-8")
multi = multi_path.read_text(encoding="utf-8")

if "HARTHMERE_FULL_BODY_ANIMATION_RUNTIME_VERSION_V6" not in player:
    insert_after = 'const HARTHMERE_BODY_MAX_BLEND_DT = 1 / 24;\n'
    v6 = '''\n// harthmere-full-animation-runtime-v6\nexport const HARTHMERE_FULL_BODY_ANIMATION_RUNTIME_VERSION_V6 =\n  "harthmere-full-body-animation-runtime-v6";\n\nconst HARTHMERE_FULL_BODY_ACTION_TIMING_V6 = {\n  creature: { windupMs: 120, impactMs: 240, recoveryMs: 360 },\n  mount: { windupMs: 160, impactMs: 280, recoveryMs: 360 },\n  ranged: { windupMs: 180, impactMs: 300, recoveryMs: 420 },\n  magic: { windupMs: 220, impactMs: 380, recoveryMs: 520 },\n  shield: { windupMs: 70, impactMs: 110, recoveryMs: 260 },\n  dodge: { windupMs: 40, impactMs: 110, recoveryMs: 360 },\n  airborne: { windupMs: 0, impactMs: 140, recoveryMs: 180 },\n  gathering: { windupMs: 180, impactMs: 360, recoveryMs: 420 },\n  crafting: { windupMs: 160, impactMs: 320, recoveryMs: 480 },\n  building: { windupMs: 150, impactMs: 300, recoveryMs: 400 },\n  social: { windupMs: 90, impactMs: 180, recoveryMs: 260 },\n  deathRespawn: { windupMs: 0, impactMs: 180, recoveryMs: 900 },\n  boss: { windupMs: 700, impactMs: 1200, recoveryMs: 900 },\n} as const;\n\nconst HARTHMERE_FULL_BODY_POSE_LAYER_RULES_V6 = {\n  rangedAim: { arms: "apply", notArms: "ifIdle" },\n  magicCast: { arms: "apply", notArms: "ifIdle" },\n  shieldBlock: { arms: "apply", notArms: "ifIdle" },\n  gathering: { arms: "apply", notArms: "ifIdle" },\n  crafting: { arms: "apply", notArms: "ifIdle" },\n  building: { arms: "apply", notArms: "ifIdle" },\n  dodge: { arms: "apply", notArms: "apply" },\n  deathRespawn: { arms: "apply", notArms: "apply" },\n} as const;\n'''
    if insert_after in player:
        player = player.replace(insert_after, insert_after + v6, 1)
    else:
        player = player.replace('const RUN_SPEED = 8;\n', 'const RUN_SPEED = 8;\n' + v6, 1)

if 'rangedAim: { fileAnimationName: "BowDraw"' not in player:
    anchor = '    attack2: { fileAnimationName: "HeavyAttack", backupFileAnimationNames: ["Attack2"], timeScale: HARTHMERE_BODY_ATTACK_TIME_SCALE_V5.attack2 },\n'
    block = '''\n\n    // harthmere-full-animation-runtime-v6\n    rangedAim: { fileAnimationName: "BowDraw", backupFileAnimationNames: ["Attack", "HeavyAttack", "Idle"] },\n    rangedRelease: { fileAnimationName: "BowRelease", backupFileAnimationNames: ["HeavyAttack", "Attack"] },\n    rangedReload: { fileAnimationName: "CrossbowReload", backupFileAnimationNames: ["ItemPutBack", "Attack"] },\n    magicCast: { fileAnimationName: "BasicMagic", backupFileAnimationNames: ["HeavyMagic", "Attack"] },\n    magicChannel: { fileAnimationName: "ChannelMagic", backupFileAnimationNames: ["BasicMagic", "Idle"] },\n    shieldBlock: { fileAnimationName: "ShieldBlock", backupFileAnimationNames: ["Block", "HitReact", "Idle"] },\n    shieldBash: { fileAnimationName: "ShieldBash", backupFileAnimationNames: ["Attack", "HeavyAttack"] },\n    dodge: { fileAnimationName: "Dodge", backupFileAnimationNames: ["Running", "Jump"] },\n    evade: { fileAnimationName: "Evade", backupFileAnimationNames: ["Running", "Jump"] },\n    stagger: { fileAnimationName: "Stagger", backupFileAnimationNames: ["HitReact", "Sick", "Fall"] },\n    knockdown: { fileAnimationName: "Knockdown", backupFileAnimationNames: ["Fall", "Death"] },\n    getUp: { fileAnimationName: "GetUp", backupFileAnimationNames: ["Idle", "Jump"] },\n    death: { fileAnimationName: "Death", backupFileAnimationNames: ["Fall"] },\n    respawn: { fileAnimationName: "Respawn", backupFileAnimationNames: ["Idle", "Waving"] },\n    land: { fileAnimationName: "Land", backupFileAnimationNames: ["Fall", "Idle"] },\n    hardLand: { fileAnimationName: "HardLand", backupFileAnimationNames: ["Fall", "HitReact", "Idle"] },\n    mountRideIdle: { fileAnimationName: "RiderIdle", backupFileAnimationNames: ["Sit", "Idle"] },\n    mountRideWalk: { fileAnimationName: "RiderWalk", backupFileAnimationNames: ["Sit", "Walking"] },\n    mountRideRun: { fileAnimationName: "RiderRun", backupFileAnimationNames: ["Sit", "Running"] },\n    mountDismount: { fileAnimationName: "Dismount", backupFileAnimationNames: ["Jump", "Sit"] },\n    mineImpact: { fileAnimationName: "Mining", backupFileAnimationNames: ["DiggingTool", "Attack"] },\n    woodcutImpact: { fileAnimationName: "Woodcutting", backupFileAnimationNames: ["DiggingTool", "Attack"] },\n    foragePickup: { fileAnimationName: "ForagePickup", backupFileAnimationNames: ["DiggingHand", "ItemPutBack"] },\n    craftStationUse: { fileAnimationName: "CraftStationUse", backupFileAnimationNames: ["DiggingTool", "ItemPutBack"] },\n    repairImpact: { fileAnimationName: "Repair", backupFileAnimationNames: ["DiggingTool", "Attack"] },\n    buildPlace: { fileAnimationName: "BuildPlace", backupFileAnimationNames: ["ItemPutBack", "DiggingTool"] },\n    socialTalk: { fileAnimationName: "TalkGesture", backupFileAnimationNames: ["Waving", "Point", "Idle"] },\n    vendorWork: { fileAnimationName: "VendorWork", backupFileAnimationNames: ["ItemPutBack", "Idle"] },\n    questGesture: { fileAnimationName: "QuestGesture", backupFileAnimationNames: ["Point", "Waving"] },\n    sleep: { fileAnimationName: "Sleep", backupFileAnimationNames: ["Sit", "Idle"] },\n    bossTelegraph: { fileAnimationName: "BossTelegraph", backupFileAnimationNames: ["HeavyAttack", "Attack"] },\n    bossPhaseTransition: { fileAnimationName: "BossPhaseTransition", backupFileAnimationNames: ["HeavyAttack", "HitReact"] },\n'''
    if anchor in player:
        player = player.replace(anchor, anchor + block, 1)
    else:
        raise SystemExit("Could not find player attack2 definition for v6 insertion")

pattern = r'(function getHarthmereWeaponSyncedEmoteWeightsV5\([\s\S]*?\)\: PlayerAnimationAction \| undefined \{\n  if \(!player\.emoteInfo\) \{\n    return;\n  \}\n)([\s\S]*?)(\n  const \{ emoteStartTime, emoteType \} = player\.emoteInfo;)'
m = re.search(pattern, player)
if m and 'getHarthmereWeaponSyncedEmoteWeightsV5(\n    player' in m.group(2):
    player = player[:m.start(2)] + player[m.end(2):]

segment = player[player.find('function getEmoteBasedWeights'):player.find('function getCameraModeWeights')]
if 'const weaponSyncedWeights = getHarthmereWeaponSyncedEmoteWeightsV5(\n    player,\n    toAnimationTime,\n  );' not in segment:
    marker = '''function getEmoteBasedWeights(\n  player: Player,\n  toAnimationTime: ToAnimationTimeFunction\n): PlayerAnimationAction | undefined {\n  if (!player.emoteInfo) {\n    return;\n  }\n\n'''
    replacement = marker + '''  const weaponSyncedWeights = getHarthmereWeaponSyncedEmoteWeightsV5(\n    player,\n    toAnimationTime,\n  );\n  if (weaponSyncedWeights) {\n    return weaponSyncedWeights;\n  }\n\n'''
    if marker in player:
        player = player.replace(marker, replacement, 1)
    else:
        raise SystemExit("Could not insert non-recursive weapon sync into getEmoteBasedWeights")

if "HARTHMERE_FULL_ANIMATION_RUNTIME_BRIDGE_VERSION_V6" not in hud:
    marker = 'function spellLabel(spellId?: string) {\n'
    hook = '''// harthmere-full-animation-runtime-v6\ntype HarthmereFullAnimationFamilyV6 =\n  | "creature" | "mount" | "ranged" | "magic" | "shield" | "dodge" | "airborne"\n  | "gathering" | "crafting" | "building" | "social" | "deathRespawn" | "boss" | "screenshot";\ntype HarthmereFullAnimationRequestV6 = {\n  family?: HarthmereFullAnimationFamilyV6;\n  action?: string;\n  phase?: string;\n  actorId?: string | number;\n  targetId?: string | number;\n  itemId?: string;\n  windupMs?: number;\n  impactMs?: number;\n  recoveryMs?: number;\n  screenshotLabel?: string;\n};\nconst HARTHMERE_FULL_ANIMATION_RUNTIME_BRIDGE_VERSION_V6 = "harthmere-full-animation-runtime-bridge-v6";\nconst HARTHMERE_FULL_ANIMATION_REQUEST_EVENT_V6 = "biomes:harthmere-animation-request-v6";\nconst HARTHMERE_FULL_ANIMATION_DEBUG_EVENT_V6 = "biomes:harthmere-animation-debug-v6";\nconst HARTHMERE_FULL_ANIMATION_FAMILIES_V6: HarthmereFullAnimationFamilyV6[] = [\n  "creature", "mount", "ranged", "magic", "shield", "dodge", "airborne",\n  "gathering", "crafting", "building", "social", "deathRespawn", "boss", "screenshot",\n];\nfunction harthmereAnimationDefaultTimingV6(family: HarthmereFullAnimationFamilyV6) {\n  switch (family) {\n    case "ranged": return { windupMs: 180, impactMs: 300, recoveryMs: 420 };\n    case "magic": return { windupMs: 220, impactMs: 380, recoveryMs: 520 };\n    case "shield": return { windupMs: 70, impactMs: 110, recoveryMs: 260 };\n    case "dodge": return { windupMs: 40, impactMs: 110, recoveryMs: 360 };\n    case "gathering": return { windupMs: 180, impactMs: 360, recoveryMs: 420 };\n    case "crafting": return { windupMs: 160, impactMs: 320, recoveryMs: 480 };\n    case "building": return { windupMs: 150, impactMs: 300, recoveryMs: 400 };\n    case "deathRespawn": return { windupMs: 0, impactMs: 180, recoveryMs: 900 };\n    case "boss": return { windupMs: 700, impactMs: 1200, recoveryMs: 900 };\n    default: return { windupMs: 120, impactMs: 240, recoveryMs: 360 };\n  }\n}\nfunction useHarthmereComprehensiveAnimationRuntimeBridgeV6() {\n  useEffect(() => {\n    if (typeof window === "undefined") return;\n    const win = window as typeof window & {\n      __harthmereAnimationRuntimeV6?: {\n        version: string;\n        families: HarthmereFullAnimationFamilyV6[];\n        log: unknown[];\n        record: (request: HarthmereFullAnimationRequestV6) => unknown;\n        request: (request: HarthmereFullAnimationRequestV6) => unknown;\n        snapshot: () => unknown;\n      };\n      __harthmereFullAnimationRuntimeDebugV6?: unknown[];\n    };\n    const record = (request: HarthmereFullAnimationRequestV6) => {\n      const family = request.family ?? "screenshot";\n      const timing = harthmereAnimationDefaultTimingV6(family);\n      const entry = {\n        at: Date.now(),\n        version: HARTHMERE_FULL_ANIMATION_RUNTIME_BRIDGE_VERSION_V6,\n        family,\n        action: request.action ?? "debug",\n        phase: request.phase ?? "start",\n        windupMs: request.windupMs ?? timing.windupMs,\n        impactMs: request.impactMs ?? timing.impactMs,\n        recoveryMs: request.recoveryMs ?? timing.recoveryMs,\n        lowerBodyLocomotionPreserved: ["ranged", "magic", "shield", "gathering", "crafting", "building", "social"].includes(family),\n        fullBodyAuthoritative: ["dodge", "airborne", "deathRespawn", "mount", "boss", "creature"].includes(family),\n        screenshotLabel: request.screenshotLabel,\n        actorId: request.actorId,\n        targetId: request.targetId,\n        itemId: request.itemId,\n      };\n      win.__harthmereFullAnimationRuntimeDebugV6 = [entry, ...(win.__harthmereFullAnimationRuntimeDebugV6 ?? [])].slice(0, 200);\n      win.dispatchEvent(new CustomEvent(HARTHMERE_FULL_ANIMATION_DEBUG_EVENT_V6, { detail: entry }));\n      return entry;\n    };\n    win.__harthmereAnimationRuntimeV6 = {\n      version: HARTHMERE_FULL_ANIMATION_RUNTIME_BRIDGE_VERSION_V6,\n      families: HARTHMERE_FULL_ANIMATION_FAMILIES_V6,\n      get log() { return win.__harthmereFullAnimationRuntimeDebugV6 ?? []; },\n      record,\n      request: (request) => {\n        win.dispatchEvent(new CustomEvent(HARTHMERE_FULL_ANIMATION_REQUEST_EVENT_V6, { detail: request }));\n        return record(request);\n      },\n      snapshot: () => ({\n        version: HARTHMERE_FULL_ANIMATION_RUNTIME_BRIDGE_VERSION_V6,\n        families: HARTHMERE_FULL_ANIMATION_FAMILIES_V6,\n        last: win.__harthmereFullAnimationRuntimeDebugV6?.[0],\n        count: win.__harthmereFullAnimationRuntimeDebugV6?.length ?? 0,\n      }),\n    };\n    const onRequest = (event: Event) => record((event as CustomEvent<HarthmereFullAnimationRequestV6>).detail ?? {});\n    const onWeapon = (event: Event) => {\n      const detail = (event as CustomEvent<Record<string, unknown>>).detail ?? {};\n      const attack = String(detail.attack ?? "");\n      if (attack === "spark") record({ family: "magic", action: "castRelease", phase: "impact", itemId: String(detail.itemId ?? "") });\n      else if (attack === "basic" || attack === "heavy") record({ family: "ranged", action: "meleeBodyAlreadyCovered", phase: "impact", itemId: String(detail.itemId ?? "") });\n    };\n    win.addEventListener(HARTHMERE_FULL_ANIMATION_REQUEST_EVENT_V6, onRequest);\n    win.addEventListener("biomes:harthmere-player-sword-visual", onWeapon);\n    record({ family: "screenshot", action: "runtimeBridgeMounted", phase: "idle" });\n    return () => {\n      win.removeEventListener(HARTHMERE_FULL_ANIMATION_REQUEST_EVENT_V6, onRequest);\n      win.removeEventListener("biomes:harthmere-player-sword-visual", onWeapon);\n    };\n  }, []);\n}\n\n'''
    if marker not in hud:
        raise SystemExit("Could not find spellLabel marker in HUD")
    hud = hud.replace(marker, hook + marker, 1)

if 'useHarthmereComprehensiveAnimationRuntimeBridgeV6();' not in hud:
    call_anchor = '  useHarthmereLocalPlayerAttackGestureBridge();\n'
    if call_anchor in hud:
        hud = hud.replace(call_anchor, call_anchor + '  useHarthmereComprehensiveAnimationRuntimeBridgeV6();\n', 1)
    else:
        raise SystemExit("Could not insert comprehensive animation bridge call")

if "HARTHMERE_NPC_FULL_ANIMATION_RUNTIME_VERSION_V6" not in npcs:
    marker = 'export const HARTHMERE_NPC_BODY_ANIMATION_SYNC_VERSION_V5 =\n  "harthmere-npc-body-animation-weapon-sync-v5";\n'
    insert = marker + '''\n// harthmere-full-animation-runtime-v6\nexport const HARTHMERE_NPC_FULL_ANIMATION_RUNTIME_VERSION_V6 =\n  "harthmere-npc-full-animation-runtime-v6";\nconst HARTHMERE_NPC_CREATURE_ANIMATION_STATES_V6 = ["idle", "walk", "run", "attack", "hit", "death", "flee", "turnInPlace"] as const;\nconst HARTHMERE_NPC_SOCIAL_ANIMATION_STATES_V6 = ["vendorIdle", "talkGesture", "questGesture", "sit", "eat", "drink", "sleep", "workLoop", "crowdEmote"] as const;\nconst HARTHMERE_NPC_BOSS_ANIMATION_STATES_V6 = ["telegraph", "phaseTransition", "areaAttack", "summon", "enrage", "wipeReset", "bossDeath"] as const;\n'''
    if marker in npcs:
        npcs = npcs.replace(marker, insert, 1)
    else:
        npcs = npcs.replace('export const npcSystem = new AnimationSystem(', '''// harthmere-full-animation-runtime-v6\nexport const HARTHMERE_NPC_FULL_ANIMATION_RUNTIME_VERSION_V6 =\n  "harthmere-npc-full-animation-runtime-v6";\nconst HARTHMERE_NPC_CREATURE_ANIMATION_STATES_V6 = ["idle", "walk", "run", "attack", "hit", "death", "flee", "turnInPlace"] as const;\nconst HARTHMERE_NPC_SOCIAL_ANIMATION_STATES_V6 = ["vendorIdle", "talkGesture", "questGesture", "sit", "eat", "drink", "sleep", "workLoop", "crowdEmote"] as const;\nconst HARTHMERE_NPC_BOSS_ANIMATION_STATES_V6 = ["telegraph", "phaseTransition", "areaAttack", "summon", "enrage", "wipeReset", "bossDeath"] as const;\n\nexport const npcSystem = new AnimationSystem(''', 1)

if "HARTHMERE_RENDERER_FULL_ANIMATION_RUNTIME_VERSION_V6" not in renderer:
    renderer += '''\n\n// harthmere-full-animation-runtime-v6\nconst HARTHMERE_RENDERER_FULL_ANIMATION_RUNTIME_VERSION_V6 =\n  "harthmere-renderer-full-animation-runtime-v6";\ntype HarthmereRendererAnimationFamilyV6 =\n  | "creature" | "mount" | "ranged" | "magic" | "shield" | "dodge" | "airborne"\n  | "gathering" | "crafting" | "building" | "social" | "deathRespawn" | "boss" | "screenshot";\nconst HARTHMERE_RENDERER_ANIMATION_DEBUG_POSES_V6: Record<HarthmereRendererAnimationFamilyV6, readonly string[]> = {\n  creature: ["idle", "walk", "run", "attack", "hit", "death", "flee", "turnInPlace"],\n  mount: ["mountIdle", "mountWalk", "mountRun", "mountStart", "mountStop", "mount", "dismount", "riderSeat"],\n  ranged: ["equip", "aimDraw", "holdAim", "release", "reload", "quiverDraw", "projectileSpawn"],\n  magic: ["equipFocus", "castStart", "channel", "castRelease", "interrupt", "vfxSpawn"],\n  shield: ["raise", "hold", "walkGuard", "turnGuard", "bash", "parry", "recoil", "lower"],\n  dodge: ["dodge", "evade", "stagger", "knockback", "knockdown", "getUp", "interruptWindow"],\n  airborne: ["jumpStart", "airborne", "fallLoop", "land", "hardLand", "armedJump", "blockingJump"],\n  gathering: ["mine", "woodcut", "fishCast", "fishReel", "foragePickup", "harvestImpact"],\n  crafting: ["stationUse", "blacksmithHammer", "tailorWork", "alchemyMix", "cookStir", "craftComplete"],\n  building: ["placePreview", "placeConfirm", "repair", "hammerImpact", "buildComplete"],\n  social: ["vendorIdle", "talkGesture", "questGesture", "sit", "eat", "drink", "sleep", "workLoop", "crowdEmote"],\n  deathRespawn: ["playerDeath", "controlsLocked", "revive", "respawn", "npcDeath", "corpseHold", "despawn"],\n  boss: ["telegraph", "phaseTransition", "areaAttack", "summon", "enrage", "wipeReset", "bossDeath"],\n  screenshot: ["baselineCapture", "poseNorth", "poseEast", "poseSouth", "poseWest", "compareDebugState"],\n};\nfunction installHarthmereRendererFullAnimationDebugV6() {\n  if (typeof window === "undefined") return;\n  const win = window as typeof window & { __harthmereRendererAnimationRuntimeV6?: unknown };\n  win.__harthmereRendererAnimationRuntimeV6 = {\n    version: HARTHMERE_RENDERER_FULL_ANIMATION_RUNTIME_VERSION_V6,\n    poses: HARTHMERE_RENDERER_ANIMATION_DEBUG_POSES_V6,\n    screenshotBaselines: ["creature_idle", "creature_attack", "mount_rider_idle", "ranged_aim", "ranged_release", "magic_channel", "magic_release", "shield_walk_guard", "shield_parry", "dodge_stagger", "jump_fall_land", "mine_impact", "woodcut_impact", "fish_cast", "craft_station", "build_repair", "vendor_talk", "npc_work_loop", "player_death", "respawn", "boss_telegraph", "boss_phase_transition", "facing_north", "facing_east", "facing_south", "facing_west"],\n  };\n}\ninstallHarthmereRendererFullAnimationDebugV6();\n'''

if "HARTHMERE_FULL_ANIMATION_REQUEST_EVENT_V6" not in multi:
    insert = '''\n// harthmere-full-animation-runtime-v6\nconst HARTHMERE_FULL_ANIMATION_REQUEST_EVENT_V6 =\n  "biomes:harthmere-animation-request-v6";\nfunction emitHarthmereFullAnimationRequestV6(detail: { family: string; action: string; phase?: string; itemId?: string; windupMs?: number; impactMs?: number; recoveryMs?: number; }) {\n  if (!isBrowser()) return;\n  window.dispatchEvent(new CustomEvent(HARTHMERE_FULL_ANIMATION_REQUEST_EVENT_V6, { detail }));\n}\n'''
    marker = 'const HARTHMERE_MULTIPLAYER_RULESET_REVISION =\n  "harthmere-gltf-action-keymap-v10";\n'
    if marker in multi:
        multi = multi.replace(marker, marker + insert, 1)
    else:
        multi = multi.replace('export const HARTHMERE_ATTACK_ANIMATION_EVENT =\n  "biomes:harthmere-attack-animation";\n', 'export const HARTHMERE_ATTACK_ANIMATION_EVENT =\n  "biomes:harthmere-attack-animation";\n' + insert, 1)

if 'emitHarthmereFullAnimationRequestV6({ family: "magic", action: attack, phase: "start" });' not in multi:
    multi = multi.replace(
        '    // harthmere-real-player-attack-gesture-v1: spark emits only after validation\n    emitAttackAnimation(attack);',
        '    // harthmere-real-player-attack-gesture-v1: spark emits only after validation\n    emitHarthmereFullAnimationRequestV6({ family: "magic", action: attack, phase: "start" });\n    emitAttackAnimation(attack);',
        1,
    )
    multi = multi.replace(
        '    // harthmere-real-player-attack-gesture-v1: physical emits only after validation\n    emitAttackAnimation(attack);',
        '    // harthmere-real-player-attack-gesture-v1: physical emits only after validation\n    emitHarthmereFullAnimationRequestV6({ family: "ranged", action: attack, phase: "start" });\n    emitAttackAnimation(attack);',
        1,
    )

player_path.write_text(player, encoding="utf-8")
hud_path.write_text(hud, encoding="utf-8")
npcs_path.write_text(npcs, encoding="utf-8")
renderer_path.write_text(renderer, encoding="utf-8")
multi_path.write_text(multi, encoding="utf-8")
print("PATCHED full animation runtime v6")
